// ✅ نسخة معدلة بالكامل (إصلاح مشكلة الخط الأخضر)
import React, { useEffect, useState, useRef } from "react";
import { Link } from "react-router-dom";

import Navbar from "components/Navbars/AuthNavbar.js";
import Footer from "components/Footers/Footer.js";

export default function Landing() {
  const texts = [
    "Hello", "Bonjour", "Ciao", "Hola", "こんにちは", "你好", "안녕하세요", "नमस्ते", "مرحبا"
  ];

  const [index, setIndex] = useState(0);
  const [selectedImage, setSelectedImage] = useState(null);
  const [hoveredId, setHoveredId] = useState(null);
  const [navbarHeight, setNavbarHeight] = useState(0);
  const [isAnyHovered, setIsAnyHovered] = useState(false);
  const [lineWidth, setLineWidth] = useState(33.33);
  const [linePosition, setLinePosition] = useState(0);

  const timeoutRef = useRef(null);
  const containerRef = useRef(null);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!isAnyHovered) {
        setIndex((prev) => (prev + 1) % texts.length);
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [isAnyHovered]);

  useEffect(() => {
    const update = () => {
      const navbar = document.querySelector("nav");
      if (navbar) setNavbarHeight(navbar.offsetHeight);
    };
    update();
    window.addEventListener("resize", update);
    return () => window.removeEventListener("resize", update);
  }, []);

  const images = [
    {
      id: 1,
      position: "left",
      url: "https://media.licdn.com/dms/image/v2/D4D22AQFq6-imvZP4iA/feedshare-shrink_2048_1536/0/1687664122353",
      title: "Code QR",
      icon: "📱",
      explainText: "Scan du Code QR"
    },
    {
      id: 2,
      position: "center",
      url: "https://img.freepik.com/premium-photo/waiter-restaurant-generative-ai_900396-28345.jpg",
      title: "Serveur",
      icon: "👨‍🍳",
      explainText: "Gestion des commandes"
    },
    {
      id: 3,
      position: "right",
      url: "https://png.pngtree.com/thumb_back/fw800/background/20221004/pngtree-closeup-of-100dollar-bill",
      title: "Facture",
      icon: "💰",
      explainText: "Calcul automatique"
    }
  ];

  const handleMouseEnter = (id, position) => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);

    setHoveredId(id);
    setIsAnyHovered(true);

    const container = containerRef.current;
    if (!container) return;
    const items = container.children;

    let width = 30;
    let pos = 0;

    if (position === "left") {
      items[0].style.flex = "0 1 50%";
      items[1].style.flex = "0 0 25%";
      items[2].style.flex = "0 0 25%";
      pos = 0;
      width = 28;
    } else if (position === "center") {
      items[0].style.flex = "0 0 20%";
      items[1].style.flex = "0 1 60%";
      items[2].style.flex = "0 0 20%";
      width = 32;
      pos = 50 - width / 2;
    } else {
      items[0].style.flex = "0 0 25%";
      items[1].style.flex = "0 0 25%";
      items[2].style.flex = "0 1 50%";
      width = 30;
      pos = 100 - width;
    }

    setLineWidth(width);
    setLinePosition(pos);
  };

  const handleMouseLeave = () => {
    timeoutRef.current = setTimeout(() => {
      setHoveredId(null);
      setIsAnyHovered(false);

      const container = containerRef.current;
      if (!container) return;

      for (let item of container.children) {
        item.style.flex = "1";
      }
    }, 150);
  };

  return (
    <>
      <Navbar transparent />
      <main>
        <div className="min-h-screen bg-black">
          <div className="flex h-screen" ref={containerRef}>
            {images.map((img) => (
              <div
                key={img.id}
                className="flex-1 relative cursor-pointer overflow-hidden"
                onMouseEnter={() => handleMouseEnter(img.id, img.position)}
                onMouseLeave={handleMouseLeave}
              >
                <img
                  src={img.url}
                  alt=""
                  className="w-full h-full object-cover"
                />

                {hoveredId === img.id && (
                  <div className="absolute inset-0 flex items-center justify-center bg-black/60">
                    <div className="text-white text-center">
                      <div className="text-5xl">{img.icon}</div>
                      <h2 className="text-2xl mt-2">{img.title}</h2>
                      <p>{img.explainText}</p>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* ✅ الخط الأخضر */}
          <div className="w-full h-2 relative bg-gray-800">
            <div
              className="absolute top-0 h-2 transition-all duration-500"
              style={{
                width: `${lineWidth}%`,
                left: `${linePosition}%`,
                background: "lime",
                opacity: isAnyHovered ? 1 : 0
              }}
            />
          </div>
        </div>
      </main>
      <Footer />
    </>
  );
}
